#include <bits/stdc++.h>
using namespace std;

const int N=5e5+10,M=1e6+10,mod=998244353;

int n,m;
int head[N],ver[M*2],nxt[M*2],tot=1;
int dfn[N],low[N],num,stk[N],top,now;
int f[M][2],ans=1;
vector<int> e[M];

void add(int u,int v){
    ver[++tot]=v,nxt[tot]=head[u],head[u]=tot;
    ver[++tot]=u,nxt[tot]=head[v],head[v]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x;
    for(int i=head[x],y;i;i=nxt[i])
        if(!dfn[y=ver[i]]){
            tarjan(y);
            low[x]=min(low[x],low[y]);
            if(low[y]>=dfn[x]){
                int z;
                now++;
                do{
                    z=stk[top--];
                    e[now].push_back(z);
                    e[z].push_back(now);
                    //printf("%d %d\n",now,z);
                }while(z!=y);
                e[now].push_back(x);
                e[x].push_back(now);
                //printf("%d %d\n",now,x);
            }
        }else
            low[x]=min(low[x],dfn[y]);
}

void dfs(int x,int fa){
    //printf("%d\n",x);
    if(x<=n)
        f[x][0]=f[x][1]=2;
    int d=1;
    for(int y:e[x])
        if(y!=fa){
            dfs(y,x);
            if(x<=n){
                f[x][0]=(f[x][0]+1ll*f[x][1]*f[y][1])%mod;
                f[x][1]=(f[x][1]+1ll*f[x][1]*f[y][1]+2ll*f[y][1])%mod;
            }else{
                f[x][0]=(f[x][0]*2+1ll*f[x][1]*f[y][1])%mod;
                f[x][1]=(f[x][1]*2+1ll*f[x][1]*f[y][1]+1ll*f[y][1]*d)%mod;
            }
            d=d*2%mod;
        }
    ans=(ans+f[x][0]*(x>n?2:1)%mod)%mod;
    //printf("%d %d %d\n",x,f[x][0],f[x][1]);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        add(u,v);
    }
    now=n;
    tarjan(1);
    dfs(1,0);
    printf("%d",ans);
    return 0;
}
